import { Kernel } from '@semantic-kernel/core';
import { VexFilter } from '@vex/sdk';

const kernel = Kernel.create();

// Vex validates planner output before execution
const planner = kernel.createPlan([
  'support|analyzeTicket',
  'billing|calculateInvoice',
  'audit|logAction'
]);

kernel.registerFilter(new VexFilter({
  rules: ['plan_validity', 'no_cross_tenant'],
  region: 'eu-west-1',
  audit: true
}));

// Safe execution
async function enterpriseWorkflow(ticketId: string, tenantId: string) {
  const result = await kernel.invoke(planner, {
    ticketId,
    tenantId,
    region: 'eu'
  });
  return result.value;
}
